{"title":"Uh Uh","artist":"Thundercat","album":"It Is What It Is","release_year":2020,"mode":"bass","part_type":"solo","part_label":"extended bass solo break (outro)","tone_type":"bass_clean","genre":"funk","tone_category":"lead","difficulty":"advanced","original_guitar":"Ibanez signature 6-string bass (Thundercat)","original_amp":"Mesa Boogie Walkabout","original_cab":"1x15 combo","original_pickup":"active humbucker, chorus/octave effects","confidence":65,"era":"2020s"}
